  ('customs-7fec267e-moex-00024', 'customs-7fec267e', 'customs-7fec267e-moex-114-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設一個追求利潤最大的獨占廠商，將價格定為12元，且其邊際收益及邊際成本交點所對應的產量 為10單位，而所對應的邊際成本為6元。若社會最大效率產量為12單位，市場需求為負斜率的直 線，且邊際成本為正斜率的直線。則此獨占廠商所造成的社會無謂損失（deadweightloss）為何？', '["4元", "6元", "12元", "16元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:21+00:00", "source_pdf_sha1": "01faaca53d6a", "answer_pdf_sha1": "56d9853120da", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "142", "s": "0805", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
